UPDATE challenges SET description_en = 'Baa Atoll in the Maldives is a UNESCO Biosphere Reserve where Hanifaru Bay hosts one of the world''s largest manta ray aggregations. Gin-clear lagoons, overwater villas, and pristine reefs define the atoll. Selected for our World 100 as the finest Maldivian atoll for both luxury and marine life.' WHERE category = 'islands' AND title_en = 'Baa Atoll, Maldives';

UPDATE challenges SET description_en = 'Bora Bora in French Polynesia is the archetypal tropical paradise—turquoise lagoon, Mount Otemanu, and luxury overwater villas on the Society Islands. Snorkeling, diving, and Polynesian culture combine in one of the world''s most photographed destinations. Selected for our World 100 as the ultimate overwater island experience.' WHERE category = 'islands' AND title_en = 'Bora Bora, French Polynesia';

UPDATE challenges SET description_en = 'Palawan in the Philippines has been named World''s Best Island by travel magazines. El Nido''s limestone karsts, Coron''s wrecks and lakes, and Puerto Princesa''s underground river showcase the country''s finest nature. Selected for our World 100 as the most biodiverse and dramatic Philippine island.' WHERE category = 'islands' AND title_en = 'Palawan, Philippines';

UPDATE challenges SET description_en = 'Komodo Island in Indonesia is the only home of the Komodo dragon. Pink Beach, coral-fringed coasts, and the Flores Sea make it a unique blend of wildlife and diving. Selected for our World 100 as the only place to see the world''s largest lizard in the wild.' WHERE category = 'islands' AND title_en = 'Komodo Island, Indonesia';

UPDATE challenges SET description_en = 'Santa Cruz in the Galápagos is the gateway to giant tortoises, the Charles Darwin Research Station, and the unique wildlife that inspired evolution theory. Ecuador''s Pacific archipelago remains one of the world''s greatest natural laboratories. Selected for our World 100 as the heart of the Galápagos experience.' WHERE category = 'islands' AND title_en = 'Santa Cruz, Galapagos';

UPDATE challenges SET description_en = 'Nosy Be off Madagascar is the "perfume island" (ylang-ylang) and a whale shark hotspot October–December. Lemurs, vanilla, and Indian Ocean beaches define this accessible Malagasy paradise. Selected for our World 100 as Madagascar''s premier island destination.' WHERE category = 'islands' AND title_en = 'Nosy Be, Madagascar';

UPDATE challenges SET description_en = 'Zanzibar combines Stone Town UNESCO heritage, spice tours, Nungwi beach, and dolphin snorkeling. Tanzania''s island offers culture, history, and coast in one. Selected for our World 100 as the most culturally rich East African island.' WHERE category = 'islands' AND title_en = 'Zanzibar, Tanzania';

UPDATE challenges SET description_en = 'Praslin in the Seychelles holds the Vallee de Mai UNESCO site—home of the coco de mer palm. Anse Lazio is often ranked among the world''s best beaches. Selected for our World 100 as the Seychelles'' most iconic nature island.' WHERE category = 'islands' AND title_en = 'Praslin, Seychelles';

UPDATE challenges SET description_en = 'Stewart Island (Rakiura) in New Zealand holds 85% of the country''s kiwi population and offers southern aurora and Foveaux Strait wilderness. Selected for our World 100 as New Zealand''s last great wilderness island.' WHERE category = 'islands' AND title_en = 'Stewart Island (Rakiura), New Zealand';

UPDATE challenges SET description_en = 'The Yasawa Islands of Fiji offer the Blue Lagoon caves, Sawa-i-lau limestone, traditional villages, and remote beaches. Selected for our World 100 as Fiji''s most authentic island chain.' WHERE category = 'islands' AND title_en = 'Yasawa Islands, Fiji';

